import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { ArrowLeft, FileText, Download, Calendar, Eye, Trash2, Share2, Clock, CheckCircle, AlertCircle } from "lucide-react";

interface Report {
  id: string;
  name: string;
  url: string;
  score: number;
  createdAt: string;
  status: "completed" | "processing" | "failed";
  type: "full" | "quick";
}

const sampleReports: Report[] = [
  { id: "1", name: "Homepage Analysis", url: "yoursite.com", score: 78, createdAt: "2026-01-10T10:30:00Z", status: "completed", type: "full" },
  { id: "2", name: "Blog Section Audit", url: "yoursite.com/blog", score: 65, createdAt: "2026-01-09T14:20:00Z", status: "completed", type: "full" },
  { id: "3", name: "Product Page Check", url: "yoursite.com/products", score: 72, createdAt: "2026-01-08T09:15:00Z", status: "completed", type: "quick" },
  { id: "4", name: "Landing Page Analysis", url: "yoursite.com/landing", score: 0, createdAt: "2026-01-10T11:00:00Z", status: "processing", type: "full" },
  { id: "5", name: "API Docs Review", url: "yoursite.com/docs", score: 81, createdAt: "2026-01-07T16:45:00Z", status: "completed", type: "full" },
];

export default function ReportsPage() {
  const navigate = useNavigate();
  const [reports, setReports] = useState<Report[]>(sampleReports);
  const [filter, setFilter] = useState<"all" | "completed" | "processing">("all");

  const deleteReport = (id: string) => {
    setReports(reports.filter(r => r.id !== id));
  };

  const filteredReports = reports.filter(r => {
    if (filter === "all") return true;
    return r.status === filter;
  });

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
  };

  const formatTime = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit" });
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return "text-emerald-400";
    if (score >= 60) return "text-yellow-400";
    if (score >= 40) return "text-orange-400";
    return "text-red-400";
  };

  const getStatusIcon = (status: Report["status"]) => {
    switch (status) {
      case "completed": return <CheckCircle className="w-4 h-4 text-emerald-400" />;
      case "processing": return <Clock className="w-4 h-4 text-yellow-400 animate-pulse" />;
      case "failed": return <AlertCircle className="w-4 h-4 text-red-400" />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      {/* Background */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black" />
        <div className="absolute bottom-0 left-1/4 w-96 h-96 bg-pink-500/5 rounded-full blur-3xl" />
      </div>

      {/* Header */}
      <div className="border-b border-slate-800/50 bg-slate-950/50 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => navigate("/")} className="p-2 rounded-lg hover:bg-slate-800/50 transition-colors">
                <ArrowLeft className="w-5 h-5 text-slate-400" />
              </button>
              <div>
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <FileText className="w-5 h-5 text-pink-400" />
                  Reports
                </h1>
                <p className="text-sm text-slate-500">View and manage your analysis reports</p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="flex bg-slate-800/50 rounded-lg p-1">
                {(["all", "completed", "processing"] as const).map((f) => (
                  <button
                    key={f}
                    onClick={() => setFilter(f)}
                    className={`px-3 py-1.5 rounded-md text-xs font-medium capitalize transition-all ${
                      filter === f
                        ? "bg-pink-500/20 text-pink-400 border border-pink-500/30"
                        : "text-slate-400 hover:text-white"
                    }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
            <p className="text-slate-400 text-sm">Total Reports</p>
            <p className="text-2xl font-bold text-white">{reports.length}</p>
          </div>
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
            <p className="text-slate-400 text-sm">Completed</p>
            <p className="text-2xl font-bold text-emerald-400">{reports.filter(r => r.status === "completed").length}</p>
          </div>
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
            <p className="text-slate-400 text-sm">Avg. Score</p>
            <p className="text-2xl font-bold text-cyan-400">
              {Math.round(reports.filter(r => r.status === "completed").reduce((a, b) => a + b.score, 0) / reports.filter(r => r.status === "completed").length) || 0}
            </p>
          </div>
        </div>

        {/* Reports List */}
        <div className="space-y-4">
          {filteredReports.map((report) => (
            <div
              key={report.id}
              className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6 hover:border-slate-600/50 transition-colors"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-xl bg-slate-800 flex items-center justify-center">
                    <FileText className="w-6 h-6 text-slate-400" />
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                      <h3 className="font-semibold text-white">{report.name}</h3>
                      {getStatusIcon(report.status)}
                    </div>
                    <p className="text-sm text-slate-500">{report.url}</p>
                    <div className="flex items-center gap-3 mt-1 text-xs text-slate-500">
                      <span className="flex items-center gap-1">
                        <Calendar className="w-3 h-3" />
                        {formatDate(report.createdAt)}
                      </span>
                      <span className="flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {formatTime(report.createdAt)}
                      </span>
                      <span className={`px-2 py-0.5 rounded-full text-xs ${
                        report.type === "full" ? "bg-purple-500/20 text-purple-400" : "bg-slate-700 text-slate-400"
                      }`}>
                        {report.type}
                      </span>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-6">
                  {report.status === "completed" && (
                    <div className="text-center">
                      <p className="text-xs text-slate-500 mb-1">Score</p>
                      <p className={`text-2xl font-bold ${getScoreColor(report.score)}`}>{report.score}</p>
                    </div>
                  )}
                  {report.status === "processing" && (
                    <div className="text-center">
                      <p className="text-xs text-yellow-400 animate-pulse">Processing...</p>
                    </div>
                  )}

                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => navigate(`/report/${report.id}`)}
                      className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors text-slate-400 hover:text-white"
                      title="View Report"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors text-slate-400 hover:text-white" title="Download">
                      <Download className="w-4 h-4" />
                    </button>
                    <button className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors text-slate-400 hover:text-white" title="Share">
                      <Share2 className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => deleteReport(report.id)}
                      className="p-2 rounded-lg bg-slate-800/50 hover:bg-red-500/20 transition-colors text-slate-400 hover:text-red-400"
                      title="Delete"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}

          {filteredReports.length === 0 && (
            <div className="text-center py-12">
              <FileText className="w-12 h-12 text-slate-600 mx-auto mb-4" />
              <p className="text-slate-400">No reports found</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
