import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Check, Loader2, Zap, Shield, Rocket, ArrowRight, Sparkles } from 'lucide-react';
import { useAuthStore } from '../app/stores/authStore';

const API_URL = import.meta.env.VITE_API_URL || '';

type BillingPeriod = 'monthly' | 'yearly';

interface TierLimits {
  scans_per_month: number;
  pages_per_scan: number;
  competitors: number;
  cache_days: number;
  exports: boolean;
  force_refresh: boolean;
  api_access: boolean;
  white_label: boolean;
}

interface TierPricing {
  key: string;
  name: string;
  displayName: string;
  pricing: {
    monthly: { amount: number; formatted: string } | null;
    yearly: { amount: number; formatted: string } | null;
  };
  features: string[];
  limits: TierLimits;
  isPaid: boolean;
}

interface PricingResponse {
  success: boolean;
  tiers: TierPricing[];
  defaultTier: string;
}

const TIER_ICONS: Record<string, React.ReactNode> = {
  observer: <Shield className="w-6 h-6" />,
  alignment: <Zap className="w-6 h-6" />,
  signal: <Rocket className="w-6 h-6" />,
};

const TIER_COLORS: Record<string, { gradient: string; border: string; glow: string }> = {
  observer: {
    gradient: 'from-slate-500 to-slate-600',
    border: 'border-slate-600/50',
    glow: 'shadow-slate-500/20',
  },
  alignment: {
    gradient: 'from-emerald-500 to-cyan-500',
    border: 'border-emerald-500/50',
    glow: 'shadow-emerald-500/30',
  },
  signal: {
    gradient: 'from-purple-500 to-pink-500',
    border: 'border-purple-500/50',
    glow: 'shadow-purple-500/30',
  },
};

const TIER_POSITIONING: Record<string, string> = {
  observer: 'baseline machine-readability check',
  alignment: 'structured extraction + export',
  signal: 'deep crawl + API + white-label',
};

const TIER_AUDIENCE: Record<string, string> = {
  observer: 'devs, founders, technical SEOs',
  alignment: 'solo founders, indie hackers, content ops',
  signal: 'agencies, studios, internal teams',
};

function PricingCard({
  tier,
  billingPeriod,
  onSelect,
  currentTier,
  isLoading,
  isHighlighted,
}: {
  tier: TierPricing;
  billingPeriod: BillingPeriod;
  onSelect: (tierKey: string) => void;
  currentTier?: string;
  isLoading?: boolean;
  isHighlighted?: boolean;
}) {
  const price = billingPeriod === 'yearly' ? tier.pricing.yearly : tier.pricing.monthly;
  const isFree = !tier.isPaid;
  const isCurrent = currentTier === tier.key;
  const colors = TIER_COLORS[tier.key] || TIER_COLORS.observer;

  return (
    <div className="relative group h-full">
      {/* Glow effect */}
      <div className={`absolute -inset-0.5 bg-gradient-to-r ${colors.gradient} rounded-2xl blur opacity-0 group-hover:opacity-40 transition duration-500 ${isHighlighted ? 'opacity-30' : ''}`} />

      <div className={`relative h-full bg-slate-900/60 backdrop-blur-xl border ${isHighlighted ? colors.border + ' border-2' : 'border-slate-700/50'} rounded-2xl p-6 flex flex-col transition-all duration-300 hover:translate-y-[-2px] ${isHighlighted ? `shadow-xl ${colors.glow}` : ''}`}>

        {/* Highlighted badge */}
        {isHighlighted && (
          <div className={`absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-1 bg-gradient-to-r ${colors.gradient} text-white text-xs font-bold tracking-wider rounded-full flex items-center gap-1`}>
            <Sparkles className="w-3 h-3" />
            POPULAR
          </div>
        )}

        {/* Header */}
        <div className="mb-4">
          <div className="flex items-center gap-3 mb-2">
            <div className={`p-2 rounded-lg bg-gradient-to-br ${colors.gradient} text-white`}>
              {TIER_ICONS[tier.key] || <Shield className="w-6 h-6" />}
            </div>
            <div>
              <h3 className="text-xl font-bold text-white">{tier.name}</h3>
              <p className="text-xs text-slate-500">{TIER_AUDIENCE[tier.key]}</p>
            </div>
          </div>
        </div>

        {/* Price */}
        <div className="mb-4">
          {isFree ? (
            <div className="flex items-baseline gap-1">
              <span className="text-4xl font-bold text-white">$0</span>
              <span className="text-slate-500">/forever</span>
            </div>
          ) : (
            <div className="flex items-baseline gap-1">
              <span className="text-4xl font-bold text-white">
                ${price?.amount || 0}
              </span>
              <span className="text-slate-500">/{billingPeriod === 'yearly' ? 'year' : 'month'}</span>
            </div>
          )}
          {billingPeriod === 'yearly' && tier.pricing.monthly && tier.pricing.yearly && (
            <p className="text-xs text-emerald-400 mt-1">
              Save ${(tier.pricing.monthly.amount * 12 - tier.pricing.yearly.amount).toFixed(0)}/year
            </p>
          )}
        </div>

        {/* Positioning */}
        <p className="text-sm text-cyan-400 font-mono mb-4 pb-4 border-b border-slate-700/50">
          → {TIER_POSITIONING[tier.key]}
        </p>

        {/* Features */}
        <ul className="space-y-2.5 mb-6 flex-grow">
          {tier.features.map((feature, idx) => (
            <li key={idx} className="flex items-start gap-2.5 text-sm text-slate-300">
              <Check className="w-4 h-4 text-emerald-500 flex-shrink-0 mt-0.5" />
              <span>{feature}</span>
            </li>
          ))}
        </ul>

        {/* Limits summary */}
        <div className="grid grid-cols-2 gap-2 mb-6 p-3 bg-slate-800/50 rounded-lg border border-slate-700/30">
          <div className="text-center">
            <p className="text-lg font-bold text-white">{tier.limits.scans_per_month}</p>
            <p className="text-xs text-slate-500">scans/mo</p>
          </div>
          <div className="text-center">
            <p className="text-lg font-bold text-white">{tier.limits.pages_per_scan}</p>
            <p className="text-xs text-slate-500">pages/scan</p>
          </div>
        </div>

        {/* CTA Button */}
        <button
          onClick={() => onSelect(tier.key)}
          disabled={isCurrent || isLoading}
          className={`w-full py-3 px-4 rounded-xl font-semibold text-sm transition-all duration-200 flex items-center justify-center gap-2 ${
            isCurrent
              ? 'bg-slate-700/50 text-slate-400 cursor-not-allowed'
              : isHighlighted
              ? `bg-gradient-to-r ${colors.gradient} text-white hover:opacity-90 shadow-lg ${colors.glow}`
              : isFree
              ? 'bg-slate-700/80 backdrop-blur-sm border border-slate-600/50 text-white hover:bg-slate-600/80'
              : 'bg-white/10 backdrop-blur-sm border border-white/20 text-white hover:bg-white/20'
          }`}
        >
          {isLoading ? (
            <Loader2 className="w-4 h-4 animate-spin" />
          ) : isCurrent ? (
            'Current Plan'
          ) : isFree ? (
            <>Start Free</>
          ) : (
            <>
              Upgrade <ArrowRight className="w-4 h-4" />
            </>
          )}
        </button>
      </div>
    </div>
  );
}

function PricingPageSkeleton() {
  return (
    <div className="grid md:grid-cols-3 gap-6">
      {[1, 2, 3].map((i) => (
        <div key={i} className="relative">
          <div className="bg-slate-900/60 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6 animate-pulse">
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 bg-slate-700 rounded-lg" />
              <div>
                <div className="h-5 w-24 bg-slate-700 rounded mb-1" />
                <div className="h-3 w-32 bg-slate-800 rounded" />
              </div>
            </div>
            <div className="h-10 w-28 bg-slate-700 rounded mb-4" />
            <div className="h-4 w-full bg-slate-800 rounded mb-4" />
            <div className="space-y-2 mb-6">
              {[1, 2, 3, 4].map((j) => (
                <div key={j} className="h-4 bg-slate-800 rounded w-full" />
              ))}
            </div>
            <div className="h-12 bg-slate-700 rounded-xl" />
          </div>
        </div>
      ))}
    </div>
  );
}

export function PricingPage() {
  const navigate = useNavigate();
  const [billingPeriod, setBillingPeriod] = useState<BillingPeriod>('yearly');
  const [tiers, setTiers] = useState<TierPricing[]>([]);
  const [isLoadingPricing, setIsLoadingPricing] = useState(true);
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { user, token, isAuthenticated } = useAuthStore();
  const currentTier = user?.tier || 'observer';

  // Fetch pricing on mount
  useEffect(() => {
    async function fetchPricing() {
      try {
        setIsLoadingPricing(true);
        setError(null);

        const response = await fetch(`${API_URL}/api/payment/pricing`);
        if (!response.ok) {
          throw new Error('Failed to load pricing');
        }

        const data: PricingResponse = await response.json();
        if (data.success && data.tiers) {
          setTiers(data.tiers);
        } else {
          throw new Error('Invalid pricing data');
        }
      } catch (err) {
        console.error('Pricing fetch error:', err);
        setError('Unable to load pricing. Please refresh the page.');
      } finally {
        setIsLoadingPricing(false);
      }
    }

    fetchPricing();
  }, []);

  async function handleSelectTier(tierKey: string) {
    if (tierKey === 'observer') {
      navigate('/');
      return;
    }

    if (!isAuthenticated || !token) {
      navigate('/auth?redirect=/pricing');
      return;
    }

    setIsCheckingOut(true);
    setError(null);

    try {
      const response = await fetch(`${API_URL}/api/payment/checkout`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ tier: tierKey, billingPeriod }),
      });

      const data = await response.json();

      if (data.success && data.url) {
        window.location.href = data.url;
      } else {
        setError(data.error || 'Failed to create checkout session');
      }
    } catch (err) {
      console.error('Checkout error:', err);
      setError('Failed to start checkout. Please try again.');
    } finally {
      setIsCheckingOut(false);
    }
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      {/* Background effects */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black" />
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-emerald-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-purple-500/10 rounded-full blur-3xl" />
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-cyan-500/5 rounded-full blur-3xl" />
        {/* Grid overlay */}
        <div
          className="absolute inset-0 opacity-[0.02]"
          style={{
            backgroundImage: `linear-gradient(rgba(255,255,255,0.1) 1px, transparent 1px),
                              linear-gradient(90deg, rgba(255,255,255,0.1) 1px, transparent 1px)`,
            backgroundSize: "50px 50px",
          }}
        />
      </div>

      <div className="max-w-6xl mx-auto px-4 py-16 relative">
        {/* Header */}
        <div className="text-center mb-12">
          <div className="inline-flex items-center gap-2 px-4 py-2 bg-slate-800/50 backdrop-blur-sm border border-slate-700/50 rounded-full text-sm text-cyan-400 mb-6">
            <Sparkles className="w-4 h-4" />
            AI Search Visibility Audit
          </div>
          <h1 className="text-4xl md:text-5xl font-bold mb-4 bg-gradient-to-r from-white via-slate-200 to-slate-400 bg-clip-text text-transparent">
            Machine Interpretation Analysis
          </h1>
          <p className="text-lg text-slate-400 max-w-2xl mx-auto">
            Schema extraction • Structural clarity • Evidence mapping • Crawler trust signals
          </p>
        </div>

        {/* Billing Toggle */}
        <div className="flex justify-center mb-12">
          <div className="relative bg-slate-800/50 backdrop-blur-xl border border-slate-700/50 rounded-full p-1.5 flex items-center">
            <button
              onClick={() => setBillingPeriod('monthly')}
              className={`relative px-6 py-2.5 rounded-full text-sm font-medium transition-all duration-300 ${
                billingPeriod === 'monthly'
                  ? 'text-white'
                  : 'text-slate-400 hover:text-white'
              }`}
            >
              {billingPeriod === 'monthly' && (
                <div className="absolute inset-0 bg-slate-700/80 rounded-full" />
              )}
              <span className="relative">Monthly</span>
            </button>
            <button
              onClick={() => setBillingPeriod('yearly')}
              className={`relative px-6 py-2.5 rounded-full text-sm font-medium transition-all duration-300 ${
                billingPeriod === 'yearly'
                  ? 'text-white'
                  : 'text-slate-400 hover:text-white'
              }`}
            >
              {billingPeriod === 'yearly' && (
                <div className="absolute inset-0 bg-gradient-to-r from-emerald-600 to-cyan-600 rounded-full" />
              )}
              <span className="relative flex items-center gap-2">
                Yearly
                <span className="px-2 py-0.5 bg-emerald-500/20 text-emerald-400 text-xs font-semibold rounded-full border border-emerald-500/30">
                  Save 40%
                </span>
              </span>
            </button>
          </div>
        </div>

        {/* Error message */}
        {error && (
          <div className="max-w-md mx-auto mb-8 p-4 bg-red-500/10 border border-red-500/30 rounded-xl text-red-400 text-sm text-center">
            {error}
          </div>
        )}

        {/* Pricing Cards */}
        {isLoadingPricing ? (
          <PricingPageSkeleton />
        ) : (
          <div className="grid md:grid-cols-3 gap-6 items-stretch">
            {tiers.map((tier) => (
              <PricingCard
                key={tier.key}
                tier={tier}
                billingPeriod={billingPeriod}
                onSelect={handleSelectTier}
                currentTier={currentTier}
                isLoading={isCheckingOut}
                isHighlighted={tier.key === 'alignment'}
              />
            ))}
          </div>
        )}

        {/* Footer features */}
        <div className="mt-16 text-center">
          <div className="inline-flex flex-wrap justify-center gap-4 p-4 bg-slate-800/30 backdrop-blur-sm border border-slate-700/30 rounded-2xl">
            {['JSON-LD scan', 'Meta tag audit', 'Heading structure', 'robots.txt check', 'Sitemap validation'].map((feature) => (
              <span key={feature} className="flex items-center gap-2 text-sm text-slate-400">
                <Check className="w-4 h-4 text-emerald-500" />
                {feature}
              </span>
            ))}
          </div>
          <p className="mt-6 text-slate-500 text-sm">
            All plans include core visibility analysis. Upgrade for deeper insights.
          </p>
        </div>

        {/* Back to Dashboard */}
        <div className="mt-8 text-center">
          <button
            onClick={() => navigate('/')}
            className="text-slate-400 hover:text-white text-sm transition-colors"
          >
            ← Back to Dashboard
          </button>
        </div>
      </div>
    </div>
  );
}

export default PricingPage;
