import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  AreaChart, Area, BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from "recharts";
import {
  Globe, TrendingUp, TrendingDown, BarChart3, PieChart as PieChartIcon,
  Calendar, Download, RefreshCw, ArrowLeft, Activity, Eye, Target, Zap,
  AlertCircle
} from "lucide-react";
import { getUserProfile } from "../app/auth/neonAuthClient";

const COLORS = ["#06b6d4", "#8b5cf6", "#ec4899", "#10b981", "#f59e0b"];

interface AnalyticsData {
  trafficData: Array<{
    date: string;
    organic: number;
    direct: number;
    referral: number;
    ai_traffic?: number;
  }>;
  platformData: Array<{
    name: string;
    value: number;
    score: number;
    impressions?: number;
    clicks?: number;
  }>;
  categoryScores: Array<{
    category: string;
    score: number;
    trend?: number;
  }>;
  summary?: {
    total_visits: number;
    ai_visibility_score: number;
    indexed_pages: number;
    avg_click_rate: number;
  };
}

async function fetchRealAnalytics(
  userId: string, 
  timeRange: string,
  signal?: AbortSignal
): Promise<AnalyticsData> {
  const apiBase = import.meta.env.VITE_API_URL?.replace(/\/$/, '') || '';
  
  if (!apiBase) {
    throw new Error('API URL not configured');
  }

  const response = await fetch(`${apiBase}/api/analytics?range=${timeRange}&user_id=${userId}`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${localStorage.getItem('auth_token')}`,
    },
    signal,
    credentials: 'same-origin',
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData?.error || `Failed to fetch analytics: ${response.status}`);
  }

  return await response.json();
}

// Fallback demo data generator
function generateDemoData(): AnalyticsData {
  const trafficData = [];
  const now = new Date();
  
  for (let i = 30; i >= 0; i--) {
    const date = new Date(now);
    date.setDate(date.getDate() - i);
    trafficData.push({
      date: date.toLocaleDateString("en-US", { month: "short", day: "numeric" }),
      organic: Math.floor(Math.random() * 5000) + 2000,
      direct: Math.floor(Math.random() * 2000) + 500,
      referral: Math.floor(Math.random() * 1000) + 200,
      ai_traffic: Math.floor(Math.random() * 800) + 100,
    });
  }

  const platformData = [
    { name: "ChatGPT", value: 35, score: 78, impressions: 12500, clicks: 850 },
    { name: "Perplexity", value: 28, score: 72, impressions: 9800, clicks: 720 },
    { name: "Google AI", value: 22, score: 65, impressions: 7200, clicks: 580 },
    { name: "Claude", value: 15, score: 81, impressions: 5100, clicks: 420 },
  ];

  const categoryScores = [
    { category: "Crawlability", score: 85, trend: 5 },
    { category: "Indexability", score: 72, trend: -2 },
    { category: "Schema", score: 68, trend: 8 },
    { category: "Content Clarity", score: 79, trend: 3 },
    { category: "Entity Trust", score: 74, trend: 0 },
    { category: "Technical", score: 81, trend: 6 },
  ];

  const summary = {
    total_visits: 45230,
    ai_visibility_score: 76,
    indexed_pages: 142,
    avg_click_rate: 3.2,
  };

  return { trafficData, platformData, categoryScores, summary };
}

export default function AnalyticsPage() {
  const navigate = useNavigate();
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [timeRange, setTimeRange] = useState<"7d" | "30d" | "90d">("30d");
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const user = getUserProfile();

  useEffect(() => {
    const controller = new AbortController();
    loadAnalytics(controller.signal);

    return () => controller.abort();
  }, [timeRange]);

  const loadAnalytics = async (signal?: AbortSignal) => {
    if (!user?.id) {
      setError('User not authenticated');
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const analyticsData = await fetchRealAnalytics(user.id, timeRange, signal);
      setData(analyticsData);
      setIsDemoMode(false);
    } catch (err: any) {
      if (err?.name === 'AbortError') return;
      
      console.error('Analytics fetch error:', err);
      
      // Fall back to demo data on error
      setData(generateDemoData());
      setIsDemoMode(true);
      setError('Unable to load live data. Showing demo analytics.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleRefresh = () => {
    loadAnalytics();
  };

  const handleExport = async () => {
    if (!data) return;

    try {
      const apiBase = import.meta.env.VITE_API_URL?.replace(/\/$/, '') || '';
      const response = await fetch(`${apiBase}/api/analytics/export?range=${timeRange}&user_id=${user?.id}`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('auth_token')}`,
        },
      });

      if (!response.ok) throw new Error('Export failed');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `analytics-${timeRange}-${new Date().toISOString().split('T')[0]}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
    } catch (err) {
      console.error('Export error:', err);
      alert('Failed to export analytics. Please try again.');
    }
  };

  if (isLoading && !data) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center">
        <div className="text-center">
          <RefreshCw className="w-12 h-12 text-cyan-400 animate-spin mx-auto mb-4" />
          <p className="text-slate-400">Loading analytics...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      {/* Background */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black" />
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-cyan-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-purple-500/5 rounded-full blur-3xl" />
      </div>

      {/* Header */}
      <div className="border-b border-slate-800/50 bg-slate-950/50 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => navigate("/")} 
                className="p-2 rounded-lg hover:bg-slate-800/50 transition-colors"
                aria-label="Go back"
              >
                <ArrowLeft className="w-5 h-5 text-slate-400" />
              </button>
              <div>
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <BarChart3 className="w-5 h-5 text-cyan-400" />
                  Analytics
                  {isDemoMode && (
                    <span className="text-xs px-2 py-1 bg-yellow-500/20 text-yellow-400 rounded-md border border-yellow-500/30">
                      Demo Mode
                    </span>
                  )}
                </h1>
                <p className="text-sm text-slate-500">Deep dive into your visibility metrics</p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              {/* Time Range Selector */}
              <div className="flex bg-slate-800/50 rounded-lg p-1">
                {(["7d", "30d", "90d"] as const).map((range) => (
                  <button
                    key={range}
                    onClick={() => setTimeRange(range)}
                    disabled={isLoading}
                    className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all disabled:opacity-50 ${
                      timeRange === range
                        ? "bg-cyan-500/20 text-cyan-400 border border-cyan-500/30"
                        : "text-slate-400 hover:text-white"
                    }`}
                  >
                    {range === "7d" ? "7 Days" : range === "30d" ? "30 Days" : "90 Days"}
                  </button>
                ))}
              </div>

              <button
                onClick={handleRefresh}
                disabled={isLoading}
                className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors disabled:opacity-50"
                aria-label="Refresh data"
              >
                <RefreshCw className={`w-5 h-5 text-slate-400 ${isLoading ? "animate-spin" : ""}`} />
              </button>

              <button 
                onClick={handleExport}
                disabled={!data || isDemoMode}
                className="p-2 rounded-lg bg-cyan-500/10 hover:bg-cyan-500/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                aria-label="Export data"
                title={isDemoMode ? "Export not available in demo mode" : "Export analytics"}
              >
                <Download className="w-5 h-5 text-cyan-400" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Error Banner */}
      {error && (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-4">
          <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-lg p-4 flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-yellow-400 flex-shrink-0 mt-0.5" />
            <div className="flex-1">
              <p className="text-yellow-400 text-sm">{error}</p>
            </div>
          </div>
        </div>
      )}

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        {/* Summary Cards */}
        {data?.summary && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Total Visits</span>
                <Eye className="w-4 h-4 text-cyan-400" />
              </div>
              <p className="text-2xl font-bold text-white">{data.summary.total_visits.toLocaleString()}</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">AI Visibility</span>
                <Zap className="w-4 h-4 text-purple-400" />
              </div>
              <p className="text-2xl font-bold text-white">{data.summary.ai_visibility_score}/100</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Indexed Pages</span>
                <Globe className="w-4 h-4 text-emerald-400" />
              </div>
              <p className="text-2xl font-bold text-white">{data.summary.indexed_pages}</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Avg Click Rate</span>
                <Target className="w-4 h-4 text-pink-400" />
              </div>
              <p className="text-2xl font-bold text-white">{data.summary.avg_click_rate}%</p>
            </div>
          </div>
        )}

        {/* Traffic Overview Chart */}
        {data && (
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
            <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
              <Activity className="w-5 h-5 text-cyan-400" />
              Traffic Overview
            </h3>
            <div className="h-80">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={data.trafficData}>
                  <defs>
                    <linearGradient id="organicGradient" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="0%" stopColor="#06b6d4" stopOpacity={0.3} />
                      <stop offset="100%" stopColor="#06b6d4" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="directGradient" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="0%" stopColor="#8b5cf6" stopOpacity={0.3} />
                      <stop offset="100%" stopColor="#8b5cf6" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="aiGradient" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="0%" stopColor="#10b981" stopOpacity={0.3} />
                      <stop offset="100%" stopColor="#10b981" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                  <XAxis 
                    dataKey="date" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: "#64748b", fontSize: 11 }} 
                  />
                  <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: "#64748b", fontSize: 11 }} 
                  />
                  <Tooltip
                    contentStyle={{ 
                      backgroundColor: "#1e293b", 
                      border: "1px solid #334155", 
                      borderRadius: "8px" 
                    }}
                    labelStyle={{ color: "#94a3b8" }}
                  />
                  <Legend />
                  <Area 
                    type="monotone" 
                    dataKey="organic" 
                    stroke="#06b6d4" 
                    fill="url(#organicGradient)" 
                    strokeWidth={2} 
                  />
                  <Area 
                    type="monotone" 
                    dataKey="direct" 
                    stroke="#8b5cf6" 
                    fill="url(#directGradient)" 
                    strokeWidth={2} 
                  />
                  <Area 
                    type="monotone" 
                    dataKey="referral" 
                    stroke="#ec4899" 
                    fill="transparent" 
                    strokeWidth={2} 
                  />
                  {data.trafficData[0]?.ai_traffic !== undefined && (
                    <Area 
                      type="monotone" 
                      dataKey="ai_traffic" 
                      stroke="#10b981" 
                      fill="url(#aiGradient)" 
                      strokeWidth={2} 
                    />
                  )}
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {/* Two Column Grid */}
        {data && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* AI Platform Distribution */}
            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
              <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                <PieChartIcon className="w-5 h-5 text-purple-400" />
                AI Platform Distribution
              </h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={data.platformData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                      label={(entry) => `${entry.name}: ${entry.value}%`}
                    >
                      {data.platformData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip
                      contentStyle={{ 
                        backgroundColor: "#1e293b", 
                        border: "1px solid #334155", 
                        borderRadius: "8px" 
                      }}
                    />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Category Scores */}
            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
              <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
                <Target className="w-5 h-5 text-emerald-400" />
                Category Scores
              </h3>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={data.categoryScores} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="#334155" horizontal={false} />
                    <XAxis 
                      type="number" 
                      domain={[0, 100]} 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: "#64748b", fontSize: 11 }} 
                    />
                    <YAxis 
                      type="category" 
                      dataKey="category" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{ fill: "#94a3b8", fontSize: 11 }} 
                      width={120} 
                    />
                    <Tooltip
                      contentStyle={{ 
                        backgroundColor: "#1e293b", 
                        border: "1px solid #334155", 
                        borderRadius: "8px" 
                      }}
                    />
                    <Bar dataKey="score" fill="#06b6d4" radius={[0, 4, 4, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
