// Remove explicit React import if using React 17+ with new JSX transform, but it's not an error.
// If you are importing any CSS files in this file or nearby, check for syntax errors in those files.
// The import below is correct for TypeScript React:
import React, { useState, useRef, useEffect } from "react";
import type { AnalysisResponse } from "../types";

const normalizeUrl = (input: string): string => {
  const trimmed = input.trim();
  if (!trimmed) return '';
  return trimmed.match(/^https?:\/\//i) ? trimmed : `https://${trimmed}`;
};

const validateUrl = (input: string): boolean => {
  try {
    const urlObj = new URL(normalizeUrl(input));
    
    // Allow localhost for development
    if (urlObj.hostname === 'localhost' || urlObj.hostname === '127.0.0.1') {
      return true;
    }
    
    // Require proper TLD (at least one dot and 2+ chars after last dot)
    const parts = urlObj.hostname.split('.');
    return parts.length >= 2 && parts[parts.length - 1].length >= 2;
  } catch {
    return false;
  }
};

const AnalyzePage: React.FC = () => {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);
  const [result, setResult] = useState<AnalysisResponse | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // Debounced URL validation for UX feedback only
  useEffect(() => {
    if (!url.trim()) {
      setValidationError(null);
      return;
    }

    const timer = setTimeout(() => {
      if (!validateUrl(url)) {
        setValidationError('Invalid URL format (e.g., example.com or https://example.com)');
      } else {
        setValidationError(null);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [url]);

  async function fetchWithRetry(
    url: string, 
    options: RequestInit, 
    retries = 2
  ): Promise<Response> {
    for (let i = 0; i <= retries; i++) {
      try {
        const response = await fetch(url, options);
        
        // Retry on rate limit
        if (response.status === 429 && i < retries) {
          await new Promise(resolve => setTimeout(resolve, 2000 * (i + 1)));
          continue;
        }
        
        return response;
      } catch (err) {
        if (i === retries) throw err;
        await new Promise(resolve => setTimeout(resolve, 1000 * (i + 1)));
      }
    }
    throw new Error('Max retries exceeded');
  }

  async function handleAnalyze() {
    const trimmedUrl = url.trim();
    
    if (!trimmedUrl) {
      setError('Please enter a valid URL to analyze');
      return;
    }

    if (!validateUrl(trimmedUrl)) {
      setError('Please enter a valid URL format (e.g., example.com or https://example.com)');
      return;
    }

    const normalizedUrl = normalizeUrl(trimmedUrl);

    // Cancel previous request if exists
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    
    abortControllerRef.current = new AbortController();

    try {
      setLoading(true);
      setError(null);
      setResult(null);

      // Get API base URL - ensure it's properly configured
      const apiBase = import.meta.env.VITE_API_URL?.replace(/\/$/, '') || '';
      
      if (!apiBase) {
        throw new Error('API URL not configured. Please set VITE_API_URL in your environment variables.');
      }

      const response = await fetchWithRetry(
        `${apiBase}/api/analyze`,
        {
          method: 'POST',
          headers: { 
            'Content-Type': 'application/json',
            'Accept': 'application/json',
          },
          body: JSON.stringify({ url: normalizedUrl }),
          signal: abortControllerRef.current.signal,
          credentials: 'omit',
          mode: 'cors',
        }
      );

      if (!response.ok) {
        const errorData: any = await response.json().catch(() => ({}));

        // Handle known backend codes
        if (errorData?.code === 'INVALID_URL') {
          throw new Error(errorData.error || 'Invalid URL format');
        }
        if (errorData?.code === 'SCRAPE_FAILED') {
          throw new Error(errorData.error || 'Unable to access website. Please check the URL and try again.');
        }
        if (errorData?.code === 'SERVER_CONFIG_ERROR') {
          throw new Error('Server configuration issue. Please try again shortly.');
        }
        if (errorData?.code === 'TIMEOUT_ERROR') {
          throw new Error('Website took too long to respond. Please try again.');
        }
        if (errorData?.code === 'NETWORK_ERROR') {
          throw new Error('Could not reach the website. Please verify the URL is correct.');
        }

        // Handle status fallbacks
        if (response.status === 429) {
          throw new Error('Rate limit exceeded. Please wait a moment and try again.');
        }
        if (response.status === 500) {
          throw new Error('Server error occurred. Please try again in a moment.');
        }
        if (response.status === 503) {
          throw new Error('Service temporarily unavailable. Please try again shortly.');
        }

        throw new Error(errorData?.error || `Analysis failed with status ${response.status}. Please try again.`);
      }

      const data: AnalysisResponse = await response.json();
      
      if (!data || typeof data !== 'object') {
        throw new Error('Invalid response from server. Please try again.');
      }

      setResult(data);

      // Analytics tracking
      if (typeof window !== 'undefined' && (window as any).gtag) {
        (window as any).gtag('event', 'analysis_complete', {
          url: data.url,
          visibility_score: data.visibility_score || data.overallScore,
        });
      }

      // Smooth scroll to results
      setTimeout(() => {
        const reportElement = document.getElementById('analysis-report');
        if (reportElement) {
          reportElement.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }, 100);

    } catch (err: any) {
      // Silently handle abort errors
      if (err?.name === 'AbortError') {
        return;
      }

      console.error('Analysis error:', err);

      // Network/fetch errors
      if (err?.name === 'TypeError' && String(err?.message || '').includes('fetch')) {
        setError('Unable to connect to the analysis server. Please check your connection and try again.');
      } else if (err?.message?.includes('API URL not configured')) {
        setError(err.message);
      } else {
        setError(err?.message || 'Analysis failed. Please try again.');
      }
    } finally {
      setLoading(false);
      abortControllerRef.current = null;
    }
  }

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl sm:text-5xl font-bold mb-4 text-white bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">
            AI Search Visibility Audit
          </h1>
          <p className="text-lg text-slate-300 max-w-2xl mx-auto">
            Discover how AI systems parse, trust, and surface your website in AI-driven search and answer engines.
          </p>
        </div>
        
        {/* Form */}
        <form
          onSubmit={(e) => {
            e.preventDefault();
            handleAnalyze();
          }}
          className="mb-8"
        >
          <div className="bg-slate-800/50 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6 shadow-2xl">
            <div className="space-y-4">
              <div className="relative">
                <input
                  type="text"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  placeholder="Enter website URL (e.g., example.com)"
                  disabled={loading}
                  className="w-full px-6 py-4 bg-slate-900/50 border border-slate-600 rounded-xl text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:border-transparent disabled:opacity-50 disabled:cursor-not-allowed transition-all text-lg"
                  aria-label="Website URL"
                  aria-invalid={!!validationError}
                  aria-describedby={validationError ? "url-error" : undefined}
                />
                {validationError && (
                  <p id="url-error" className="mt-2 text-sm text-yellow-400 flex items-center gap-2">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                    </svg>
                    {validationError}
                  </p>
                )}
              </div>
              
              <button
                type="submit"
                disabled={loading || !url.trim()}
                className="w-full px-6 py-4 bg-gradient-to-r from-cyan-500 to-purple-500 text-white rounded-xl hover:from-cyan-600 hover:to-purple-600 disabled:from-slate-600 disabled:to-slate-600 disabled:cursor-not-allowed transition-all font-semibold text-lg shadow-lg hover:shadow-cyan-500/25 focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:ring-offset-2 focus:ring-offset-slate-900"
                aria-busy={loading}
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-3">
                    <svg className="animate-spin h-5 w-5" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                    </svg>
                    Analyzing...
                  </span>
                ) : (
                  "Run AI Visibility Audit"
                )}
              </button>
            </div>
          </div>
        </form>

        {/* Error Display */}
        {error && (
          <div 
            className="mb-8 p-6 bg-red-900/20 border border-red-500/50 rounded-2xl backdrop-blur-xl"
            role="alert"
            aria-live="polite"
          >
            <div className="flex items-start gap-3">
              <svg className="w-6 h-6 text-red-400 flex-shrink-0 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
              </svg>
              <div>
                <strong className="font-semibold text-red-300">Error</strong>
                <p className="text-red-200 mt-1">{error}</p>
              </div>
            </div>
          </div>
        )}

        {/* Results Display */}
        {result && (
          <div id="analysis-report" className="bg-slate-800/50 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-8 shadow-2xl">
            {/* Header */}
            <div className="mb-8 pb-6 border-b border-slate-700">
              <h2 className="text-3xl font-bold text-white mb-2">
                Analysis Results
              </h2>
              <p className="text-slate-400 flex items-center gap-2">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" />
                </svg>
                {result.url || url}
              </p>
            </div>
            
            {/* Score Display */}
            <div className="mb-8 p-6 bg-gradient-to-br from-cyan-500/10 to-purple-500/10 border border-cyan-500/20 rounded-xl">
              <div className="flex items-center justify-between">
                <div>
                  <span className="text-lg font-medium text-slate-300 block mb-1">AI Visibility Score</span>
                  {result.verdict && (
                    <span className="text-sm text-slate-400">{result.verdict}</span>
                  )}
                </div>
                <div className="text-right">
                  <div className="text-5xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">
                    {result.visibility_score || result.overallScore || 0}
                  </div>
                  <div className="text-sm text-slate-400 mt-1">out of 100</div>
                </div>
              </div>
            </div>

            {/* Categories Grid */}
            {result.categories && result.categories.length > 0 && (
              <div className="mb-8">
                <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
                  <svg className="w-5 h-5 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" />
                  </svg>
                  Category Breakdown
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {result.categories.map((category: any, index: number) => (
                    <div 
                      key={index} 
                      className="p-4 bg-slate-900/50 border border-slate-700 rounded-xl hover:border-cyan-500/50 transition-colors"
                    >
                      <div className="flex items-center justify-between mb-2">
                        <span className="font-medium text-white">{category.name}</span>
                        <span className={`px-2 py-1 rounded-md text-xs font-semibold ${
                          category.status === 'excellent' ? 'bg-green-500/20 text-green-400' :
                          category.status === 'good' ? 'bg-blue-500/20 text-blue-400' :
                          category.status === 'needs-work' ? 'bg-yellow-500/20 text-yellow-400' :
                          'bg-red-500/20 text-red-400'
                        }`}>
                          {category.status}
                        </span>
                      </div>
                      <div className="flex items-center gap-3 mb-2">
                        <div className="flex-1 bg-slate-800 rounded-full h-2">
                          <div 
                            className={`h-2 rounded-full ${
                              category.score >= 90 ? 'bg-green-500' :
                              category.score >= 70 ? 'bg-blue-500' :
                              category.score >= 50 ? 'bg-yellow-500' :
                              'bg-red-500'
                            }`}
                            style={{ width: `${category.score}%` }}
                          />
                        </div>
                        <span className="text-sm font-semibold text-white">{category.score}</span>
                      </div>
                      <p className="text-sm text-slate-400">{category.finding}</p>
                      {category.fix && (
                        <p className="text-sm text-cyan-400 mt-2">💡 {category.fix}</p>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Critical Fixes */}
            {result.criticalFixes && result.criticalFixes.length > 0 && (
              <div className="mb-8">
                <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
                  <svg className="w-5 h-5 text-red-400" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                  </svg>
                  Critical Issues
                </h3>
                <div className="space-y-3">
                  {result.criticalFixes.map((fix: string, index: number) => (
                    <div key={index} className="p-4 bg-red-900/10 border border-red-500/30 rounded-lg">
                      <p className="text-red-200">{fix}</p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Quick Wins */}
            {result.quickWins && result.quickWins.length > 0 && (
              <div className="mb-8">
                <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
                  <svg className="w-5 h-5 text-green-400" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z" clipRule="evenodd" />
                  </svg>
                  Quick Wins
                </h3>
                <div className="space-y-3">
                  {result.quickWins.map((win: string, index: number) => (
                    <div key={index} className="p-4 bg-green-900/10 border border-green-500/30 rounded-lg">
                      <p className="text-green-200">{win}</p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Metadata */}
            {result.metadata && (
              <div className="pt-6 border-t border-slate-700">
                <div className="flex flex-wrap gap-6 text-sm text-slate-400">
                  {result.metadata.scannedAt && (
                    <div className="flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                      Scanned: {new Date(result.metadata.scannedAt).toLocaleString()}
                    </div>
                  )}
                  {result.metadata.loadTime && (
                    <div className="flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                      </svg>
                      Load time: {result.metadata.loadTime}ms
                    </div>
                  )}
                  {result.metadata.pageSize && (
                    <div className="flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4" />
                      </svg>
                      Size: {(result.metadata.pageSize / 1024).toFixed(2)} KB
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default AnalyzePage;