import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadarChart, Radar, PolarGrid, PolarAngleAxis, PolarRadiusAxis } from "recharts";
import { ArrowLeft, Users, Plus, Trash2, ExternalLink, TrendingUp, TrendingDown, Globe, BarChart3 } from "lucide-react";

interface Competitor {
  id: string;
  name: string;
  domain: string;
  visibilityScore: number;
  previousScore: number;
  keywords: number;
  traffic: number;
}

const sampleCompetitors: Competitor[] = [
  { id: "1", name: "Competitor A", domain: "competitor-a.com", visibilityScore: 72, previousScore: 68, keywords: 1250, traffic: 185000 },
  { id: "2", name: "Competitor B", domain: "competitor-b.io", visibilityScore: 65, previousScore: 70, keywords: 890, traffic: 142000 },
  { id: "3", name: "Competitor C", domain: "competitor-c.com", visibilityScore: 81, previousScore: 79, keywords: 1680, traffic: 210000 },
];

const comparisonData = [
  { metric: "Crawlability", you: 85, compA: 78, compB: 72, compC: 88 },
  { metric: "Schema", you: 72, compA: 68, compB: 81, compC: 75 },
  { metric: "Content", you: 79, compA: 82, compB: 69, compC: 77 },
  { metric: "Technical", you: 81, compA: 75, compB: 78, compC: 83 },
  { metric: "Entity Trust", you: 74, compA: 71, compB: 65, compC: 79 },
  { metric: "AI Readability", you: 78, compA: 69, compB: 74, compC: 81 },
];

const radarData = [
  { subject: "Crawlability", You: 85, Avg: 75 },
  { subject: "Schema", You: 72, Avg: 70 },
  { subject: "Content", You: 79, Avg: 76 },
  { subject: "Technical", You: 81, Avg: 77 },
  { subject: "Entity Trust", You: 74, Avg: 71 },
  { subject: "AI Ready", You: 78, Avg: 73 },
];

export default function CompetitorsPage() {
  const navigate = useNavigate();
  const [competitors, setCompetitors] = useState<Competitor[]>(sampleCompetitors);
  const [newDomain, setNewDomain] = useState("");

  const addCompetitor = () => {
    if (!newDomain.trim()) return;
    const newComp: Competitor = {
      id: Date.now().toString(),
      name: newDomain.split(".")[0],
      domain: newDomain,
      visibilityScore: Math.floor(Math.random() * 30) + 50,
      previousScore: Math.floor(Math.random() * 30) + 50,
      keywords: Math.floor(Math.random() * 1000) + 500,
      traffic: Math.floor(Math.random() * 150000) + 50000,
    };
    setCompetitors([...competitors, newComp]);
    setNewDomain("");
  };

  const removeCompetitor = (id: string) => {
    setCompetitors(competitors.filter(c => c.id !== id));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      {/* Background */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black" />
        <div className="absolute top-0 right-1/4 w-96 h-96 bg-purple-500/5 rounded-full blur-3xl" />
      </div>

      {/* Header */}
      <div className="border-b border-slate-800/50 bg-slate-950/50 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button onClick={() => navigate("/")} className="p-2 rounded-lg hover:bg-slate-800/50 transition-colors">
                <ArrowLeft className="w-5 h-5 text-slate-400" />
              </button>
              <div>
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <Users className="w-5 h-5 text-purple-400" />
                  Competitors
                </h1>
                <p className="text-sm text-slate-500">Analyze and compare with your competitors</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        {/* Add Competitor */}
        <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
          <h3 className="text-lg font-semibold text-white mb-4">Add Competitor</h3>
          <div className="flex gap-3">
            <input
              type="text"
              value={newDomain}
              onChange={(e) => setNewDomain(e.target.value)}
              placeholder="competitor-domain.com"
              className="flex-1 px-4 py-2.5 bg-slate-800/50 border border-slate-700/50 rounded-xl text-sm text-white placeholder-slate-500 focus:outline-none focus:border-purple-500/50"
              onKeyDown={(e) => e.key === "Enter" && addCompetitor()}
            />
            <button
              onClick={addCompetitor}
              className="px-6 py-2.5 bg-purple-500/20 hover:bg-purple-500/30 text-purple-400 rounded-xl text-sm font-medium transition-colors flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Add
            </button>
          </div>
        </div>

        {/* Competitors List */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {/* Your Site Card */}
          <div className="bg-gradient-to-br from-cyan-500/20 to-purple-500/20 backdrop-blur-xl border border-cyan-500/30 rounded-2xl p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-cyan-500 to-purple-600 flex items-center justify-center">
                  <Globe className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h4 className="font-semibold text-white">Your Site</h4>
                  <p className="text-xs text-slate-400">yoursite.com</p>
                </div>
              </div>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-slate-400 text-sm">Visibility Score</span>
                <span className="text-2xl font-bold text-cyan-400">78</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-slate-400 text-sm">Keywords</span>
                <span className="text-white font-medium">1,450</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-slate-400 text-sm">Est. Traffic</span>
                <span className="text-white font-medium">198K</span>
              </div>
            </div>
          </div>

          {/* Competitor Cards */}
          {competitors.map((comp) => {
            const change = comp.visibilityScore - comp.previousScore;
            return (
              <div key={comp.id} className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6 hover:border-slate-600/50 transition-colors">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-slate-800 flex items-center justify-center text-slate-400">
                      {comp.name.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h4 className="font-semibold text-white">{comp.name}</h4>
                      <p className="text-xs text-slate-500">{comp.domain}</p>
                    </div>
                  </div>
                  <button onClick={() => removeCompetitor(comp.id)} className="p-1.5 rounded-lg hover:bg-slate-700/50 transition-colors text-slate-500 hover:text-red-400">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-slate-400 text-sm">Visibility</span>
                    <div className="flex items-center gap-2">
                      <span className="text-xl font-bold text-white">{comp.visibilityScore}</span>
                      <span className={`text-xs flex items-center gap-0.5 ${change >= 0 ? "text-emerald-400" : "text-red-400"}`}>
                        {change >= 0 ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                        {change >= 0 ? "+" : ""}{change}
                      </span>
                    </div>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-slate-400 text-sm">Keywords</span>
                    <span className="text-white font-medium">{comp.keywords.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-slate-400 text-sm">Est. Traffic</span>
                    <span className="text-white font-medium">{(comp.traffic / 1000).toFixed(0)}K</span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Comparison Charts */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Bar Chart Comparison */}
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
            <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
              <BarChart3 className="w-5 h-5 text-cyan-400" />
              Score Comparison
            </h3>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={comparisonData} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" horizontal={false} />
                  <XAxis type="number" domain={[0, 100]} axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 10 }} />
                  <YAxis type="category" dataKey="metric" axisLine={false} tickLine={false} tick={{ fill: "#94a3b8", fontSize: 10 }} width={80} />
                  <Tooltip contentStyle={{ backgroundColor: "#1e293b", border: "1px solid #334155", borderRadius: "8px" }} />
                  <Bar dataKey="you" fill="#06b6d4" name="You" radius={[0, 2, 2, 0]} />
                  <Bar dataKey="compA" fill="#8b5cf6" name="Comp A" radius={[0, 2, 2, 0]} />
                  <Bar dataKey="compC" fill="#ec4899" name="Comp C" radius={[0, 2, 2, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Radar Chart */}
          <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
            <h3 className="text-lg font-semibold text-white mb-4">Your Position vs Average</h3>
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <RadarChart data={radarData}>
                  <PolarGrid stroke="#334155" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: "#94a3b8", fontSize: 10 }} />
                  <PolarRadiusAxis angle={30} domain={[0, 100]} tick={{ fill: "#64748b", fontSize: 10 }} />
                  <Radar name="You" dataKey="You" stroke="#06b6d4" fill="#06b6d4" fillOpacity={0.3} />
                  <Radar name="Avg" dataKey="Avg" stroke="#8b5cf6" fill="#8b5cf6" fillOpacity={0.1} />
                  <Tooltip contentStyle={{ backgroundColor: "#1e293b", border: "1px solid #334155", borderRadius: "8px" }} />
                </RadarChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
