import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  ArrowLeft, Search, TrendingUp, TrendingDown, Filter, Download,
  Plus, Trash2, Star, StarOff, ExternalLink, BarChart2, RefreshCw,
  AlertCircle, Calendar, Eye, Target
} from "lucide-react";
import { useAuthStore } from "../app/stores/authStore";

interface Keyword {
  id: string;
  keyword: string;
  position: number;
  previousPosition: number;
  volume: number;
  difficulty: number;
  traffic: number;
  starred: boolean;
  url?: string;
  lastChecked?: string;
  trending?: 'up' | 'down' | 'stable';
}

interface KeywordStats {
  total: number;
  topTen: number;
  avgPosition: number;
  totalTraffic: number;
}

const API_URL = import.meta.env.VITE_API_URL || '';

export default function KeywordsPage() {
  const navigate = useNavigate();
  const { user, token, isAuthenticated } = useAuthStore();
  
  const [keywords, setKeywords] = useState<Keyword[]>([]);
  const [stats, setStats] = useState<KeywordStats | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [sortBy, setSortBy] = useState<"position" | "volume" | "traffic" | "difficulty">("position");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("asc");
  const [filterStarred, setFilterStarred] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedKeywords, setSelectedKeywords] = useState<Set<string>>(new Set());

  // Fetch keywords on mount
  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
      return;
    }
    fetchKeywords();
  }, [isAuthenticated, navigate]);

  const fetchKeywords = async () => {
    if (!token) return;

    setLoading(true);
    setError(null);

    try {
      const response = await fetch(`${API_URL}/api/keywords`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        credentials: 'omit',
      });

      if (!response.ok) {
        throw new Error('Failed to fetch keywords');
      }

      const data = await response.json();
      setKeywords(data.keywords || []);
      setStats(data.stats || calculateStats(data.keywords || []));
    } catch (err: any) {
      console.error('Error fetching keywords:', err);
      setError(err.message || 'Failed to load keywords');
      // Fallback to demo data
      setKeywords(generateDemoKeywords());
      setStats(calculateStats(generateDemoKeywords()));
    } finally {
      setLoading(false);
    }
  };

  const toggleStar = async (id: string) => {
    const keyword = keywords.find(k => k.id === id);
    if (!keyword) return;

    // Optimistic update
    setKeywords(prev => prev.map(kw =>
      kw.id === id ? { ...kw, starred: !kw.starred } : kw
    ));

    try {
      await fetch(`${API_URL}/api/keywords/${id}/star`, {
        method: 'PATCH',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ starred: !keyword.starred }),
        credentials: 'omit',
      });
    } catch (err) {
      console.error('Error updating star status:', err);
      // Revert on error
      setKeywords(prev => prev.map(kw =>
        kw.id === id ? { ...kw, starred: keyword.starred } : kw
      ));
    }
  };

  const handleExport = async () => {
    try {
      const response = await fetch(`${API_URL}/api/keywords/export?format=csv`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
        credentials: 'omit',
      });

      if (!response.ok) throw new Error('Export failed');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `keywords-${new Date().toISOString().slice(0, 10)}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
    } catch (err) {
      console.error('Export error:', err);
      alert('Failed to export keywords');
    }
  };

  const handleDeleteSelected = async () => {
    if (selectedKeywords.size === 0) return;
    
    if (!confirm(`Delete ${selectedKeywords.size} keyword(s)?`)) return;

    try {
      await fetch(`${API_URL}/api/keywords/bulk-delete`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ ids: Array.from(selectedKeywords) }),
        credentials: 'omit',
      });

      setKeywords(prev => prev.filter(k => !selectedKeywords.has(k.id)));
      setSelectedKeywords(new Set());
    } catch (err) {
      console.error('Delete error:', err);
      alert('Failed to delete keywords');
    }
  };

  const toggleSelectKeyword = (id: string) => {
    setSelectedKeywords(prev => {
      const newSet = new Set(prev);
      if (newSet.has(id)) {
        newSet.delete(id);
      } else {
        newSet.add(id);
      }
      return newSet;
    });
  };

  const toggleSort = (field: typeof sortBy) => {
    if (sortBy === field) {
      setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(field);
      setSortOrder('asc');
    }
  };

  const filteredKeywords = keywords
    .filter(kw => kw.keyword.toLowerCase().includes(searchQuery.toLowerCase()))
    .filter(kw => !filterStarred || kw.starred)
    .sort((a, b) => {
      let comparison = 0;
      
      if (sortBy === "position") comparison = a.position - b.position;
      else if (sortBy === "volume") comparison = b.volume - a.volume;
      else if (sortBy === "traffic") comparison = b.traffic - a.traffic;
      else if (sortBy === "difficulty") comparison = a.difficulty - b.difficulty;
      
      return sortOrder === 'asc' ? comparison : -comparison;
    });

  const getDifficultyColor = (diff: number) => {
    if (diff < 40) return "text-emerald-400";
    if (diff < 60) return "text-yellow-400";
    return "text-red-400";
  };

  const getPositionChange = (current: number, previous: number) => {
    const change = previous - current;
    if (change > 0) return { icon: TrendingUp, color: "text-emerald-400", text: `+${change}` };
    if (change < 0) return { icon: TrendingDown, color: "text-red-400", text: `${change}` };
    return { icon: null, color: "text-slate-500", text: "-" };
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center">
        <div className="text-center">
          <RefreshCw className="w-12 h-12 text-cyan-400 animate-spin mx-auto mb-4" />
          <p className="text-slate-400">Loading keywords...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      {/* Background */}
      <div className="fixed inset-0 -z-10">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-900 via-slate-950 to-black" />
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-cyan-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-purple-500/5 rounded-full blur-3xl" />
      </div>

      {/* Header */}
      <div className="border-b border-slate-800/50 bg-slate-950/50 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => navigate("/")} 
                className="p-2 rounded-lg hover:bg-slate-800/50 transition-colors"
                aria-label="Go back"
              >
                <ArrowLeft className="w-5 h-5 text-slate-400" />
              </button>
              <div>
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <BarChart2 className="w-5 h-5 text-cyan-400" />
                  Keywords
                </h1>
                <p className="text-sm text-slate-500">Track and manage your ranking keywords</p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              {selectedKeywords.size > 0 && (
                <button 
                  onClick={handleDeleteSelected}
                  className="px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
                >
                  <Trash2 className="w-4 h-4" />
                  Delete ({selectedKeywords.size})
                </button>
              )}
              <button 
                onClick={fetchKeywords}
                disabled={loading}
                className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors disabled:opacity-50"
                aria-label="Refresh"
              >
                <RefreshCw className={`w-5 h-5 text-slate-400 ${loading ? 'animate-spin' : ''}`} />
              </button>
              <button 
                onClick={() => navigate('/keywords/add')}
                className="px-4 py-2 bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
              >
                <Plus className="w-4 h-4" />
                Add Keywords
              </button>
              <button 
                onClick={handleExport}
                className="p-2 rounded-lg bg-slate-800/50 hover:bg-slate-700/50 transition-colors"
                aria-label="Export"
              >
                <Download className="w-5 h-5 text-slate-400" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Error Banner */}
        {error && (
          <div className="mb-6 p-4 bg-yellow-500/10 border border-yellow-500/30 rounded-xl flex items-center gap-3">
            <AlertCircle className="w-5 h-5 text-yellow-400 flex-shrink-0" />
            <div className="flex-1">
              <p className="text-yellow-400 text-sm">{error}</p>
              <p className="text-yellow-400/70 text-xs mt-1">Showing demo data</p>
            </div>
          </div>
        )}

        {/* Stats Cards */}
        {stats && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Total Keywords</span>
                <Target className="w-4 h-4 text-cyan-400" />
              </div>
              <p className="text-2xl font-bold text-white">{stats.total}</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Top 10 Rankings</span>
                <TrendingUp className="w-4 h-4 text-emerald-400" />
              </div>
              <p className="text-2xl font-bold text-white">{stats.topTen}</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Avg Position</span>
                <BarChart2 className="w-4 h-4 text-purple-400" />
              </div>
              <p className="text-2xl font-bold text-white">#{stats.avgPosition.toFixed(1)}</p>
            </div>

            <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-xl p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm text-slate-400">Total Traffic</span>
                <Eye className="w-4 h-4 text-pink-400" />
              </div>
              <p className="text-2xl font-bold text-white">{stats.totalTraffic.toLocaleString()}</p>
            </div>
          </div>
        )}

        {/* Filters */}
        <div className="flex flex-wrap items-center gap-4 mb-6">
          <div className="relative flex-1 min-w-[250px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search keywords..."
              className="w-full pl-10 pr-4 py-2.5 bg-slate-800/50 border border-slate-700/50 rounded-xl text-sm text-white placeholder-slate-500 focus:outline-none focus:border-cyan-500/50"
            />
          </div>

          <button
            onClick={() => setFilterStarred(!filterStarred)}
            className={`px-4 py-2.5 rounded-xl text-sm font-medium transition-colors flex items-center gap-2 ${
              filterStarred 
                ? "bg-yellow-500/20 text-yellow-400 border border-yellow-500/30" 
                : "bg-slate-800/50 text-slate-400 border border-slate-700/50 hover:bg-slate-800"
            }`}
          >
            <Star className="w-4 h-4" />
            Starred {filterStarred && `(${keywords.filter(k => k.starred).length})`}
          </button>

          <div className="text-sm text-slate-400">
            Showing {filteredKeywords.length} of {keywords.length} keywords
          </div>
        </div>

        {/* Keywords Table */}
        <div className="bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl overflow-hidden">
          {filteredKeywords.length === 0 ? (
            <div className="p-12 text-center">
              <BarChart2 className="w-16 h-16 text-slate-700 mx-auto mb-4" />
              <h3 className="text-lg font-semibold text-slate-400 mb-2">No keywords found</h3>
              <p className="text-slate-500 mb-6">
                {searchQuery ? 'Try adjusting your search' : 'Add your first keyword to start tracking'}
              </p>
              {!searchQuery && (
                <button 
                  onClick={() => navigate('/keywords/add')}
                  className="px-6 py-3 bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 rounded-lg font-medium transition-colors inline-flex items-center gap-2"
                >
                  <Plus className="w-5 h-5" />
                  Add Keywords
                </button>
              )}
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-slate-700/50">
                    <th className="px-6 py-4 text-left w-8">
                      <input
                        type="checkbox"
                        checked={selectedKeywords.size === filteredKeywords.length && filteredKeywords.length > 0}
                        onChange={(e) => {
                          if (e.target.checked) {
                            setSelectedKeywords(new Set(filteredKeywords.map(k => k.id)));
                          } else {
                            setSelectedKeywords(new Set());
                          }
                        }}
                        className="rounded border-slate-600 bg-slate-800 text-cyan-500 focus:ring-cyan-500"
                      />
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">
                      Keyword
                    </th>
                    <th 
                      className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider cursor-pointer hover:text-cyan-400 transition-colors"
                      onClick={() => toggleSort('position')}
                    >
                      Position {sortBy === 'position' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider">
                      Change
                    </th>
                    <th 
                      className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider cursor-pointer hover:text-cyan-400 transition-colors"
                      onClick={() => toggleSort('volume')}
                    >
                      Volume {sortBy === 'volume' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th 
                      className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider cursor-pointer hover:text-cyan-400 transition-colors"
                      onClick={() => toggleSort('difficulty')}
                    >
                      Difficulty {sortBy === 'difficulty' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th 
                      className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider cursor-pointer hover:text-cyan-400 transition-colors"
                      onClick={() => toggleSort('traffic')}
                    >
                      Traffic {sortBy === 'traffic' && (sortOrder === 'asc' ? '↑' : '↓')}
                    </th>
                    <th className="px-6 py-4 text-center text-xs font-medium text-slate-500 uppercase tracking-wider">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {filteredKeywords.map((kw) => {
                    const change = getPositionChange(kw.position, kw.previousPosition);
                    return (
                      <tr 
                        key={kw.id} 
                        className={`hover:bg-slate-800/30 transition-colors ${
                          selectedKeywords.has(kw.id) ? 'bg-cyan-500/5' : ''
                        }`}
                      >
                        <td className="px-6 py-4">
                          <input
                            type="checkbox"
                            checked={selectedKeywords.has(kw.id)}
                            onChange={() => toggleSelectKeyword(kw.id)}
                            className="rounded border-slate-600 bg-slate-800 text-cyan-500 focus:ring-cyan-500"
                          />
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <button 
                              onClick={() => toggleStar(kw.id)} 
                              className="text-slate-500 hover:text-yellow-400 transition-colors"
                            >
                              {kw.starred ? (
                                <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
                              ) : (
                                <StarOff className="w-4 h-4" />
                              )}
                            </button>
                            <div>
                              <span className="text-white font-medium block">{kw.keyword}</span>
                              {kw.url && (
                                <span className="text-xs text-slate-500">{kw.url}</span>
                              )}
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className={`font-bold ${
                            kw.position <= 3 ? 'text-emerald-400' :
                            kw.position <= 10 ? 'text-cyan-400' :
                            kw.position <= 20 ? 'text-yellow-400' :
                            'text-slate-400'
                          }`}>
                            #{kw.position}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className={`flex items-center justify-center gap-1 ${change.color}`}>
                            {change.icon && <change.icon className="w-4 h-4" />}
                            {change.text}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center text-slate-300">
                          {kw.volume >= 1000 ? `${(kw.volume / 1000).toFixed(1)}K` : kw.volume}
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className={getDifficultyColor(kw.difficulty)}>
                            {kw.difficulty}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-center text-emerald-400">
                          +{kw.traffic.toLocaleString()}
                        </td>
                        <td className="px-6 py-4 text-center">
                          <div className="flex items-center justify-center gap-2">
                            {kw.url && (
                              <a
                                href={kw.url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="p-1.5 rounded-lg hover:bg-slate-700/50 transition-colors text-slate-400 hover:text-white"
                              >
                                <ExternalLink className="w-4 h-4" />
                              </a>
                            )}
                            <button 
                              onClick={() => navigate(`/keywords/${kw.id}`)}
                              className="p-1.5 rounded-lg hover:bg-slate-700/50 transition-colors text-slate-400 hover:text-white"
                            >
                              <BarChart2 className="w-4 h-4" />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

// Helper functions
function calculateStats(keywords: Keyword[]): KeywordStats {
  return {
    total: keywords.length,
    topTen: keywords.filter(k => k.position <= 10).length,
    avgPosition: keywords.length > 0 
      ? keywords.reduce((sum, k) => sum + k.position, 0) / keywords.length 
      : 0,
    totalTraffic: keywords.reduce((sum, k) => sum + k.traffic, 0),
  };
}

function generateDemoKeywords(): Keyword[] {
  return [
    { id: "1", keyword: "AI content tools", position: 12, previousPosition: 15, volume: 12000, difficulty: 45, traffic: 2800, starred: true, url: "https://example.com/ai-tools" },
    { id: "2", keyword: "Machine learning software", position: 8, previousPosition: 12, volume: 18000, difficulty: 62, traffic: 4200, starred: true },
    { id: "3", keyword: "SEO optimization tips", position: 23, previousPosition: 19, volume: 15000, difficulty: 38, traffic: 1800, starred: false },
    { id: "4", keyword: "Artificial intelligence trends", position: 5, previousPosition: 7, volume: 22000, difficulty: 71, traffic: 5600, starred: true },
    { id: "5", keyword: "AI search algorithms", position: 18, previousPosition: 22, volume: 8500, difficulty: 55, traffic: 1200, starred: false },
    { id: "6", keyword: "Natural language processing", position: 31, previousPosition: 28, volume: 9200, difficulty: 68, traffic: 720, starred: false },
    { id: "7", keyword: "Deep learning frameworks", position: 14, previousPosition: 16, volume: 11000, difficulty: 59, traffic: 2100, starred: false },
    { id: "8", keyword: "AI visibility score", position: 3, previousPosition: 5, volume: 4500, difficulty: 32, traffic: 3200, starred: true },
  ];
}