// Deterministic RNG helpers (xmur3 + mulberry32)
function xmur3(str: string) {
  let h = 1779033703 ^ str.length;
  for (let i = 0; i < str.length; i++) {
    h = Math.imul(h ^ str.charCodeAt(i), 3432918353);
    h = (h << 13) | (h >>> 19);
  }
  return function() {
    h = Math.imul(h ^ (h >>> 16), 2246822507);
    h = Math.imul(h ^ (h >>> 13), 3266489909);
    return (h ^= h >>> 16) >>> 0;
  };
}

function mulberry32(a: number) {
  return function() {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// Transform API response to dashboard data
function transformApiResponse(response: AnalysisResponse): DashboardData {
  const trendData: TrendDataPoint[] = [];
  const now = new Date();

  const seedSource = (response.url || response.domain_intelligence?.domain || 'global').toString();
  const seed = xmur3(seedSource)();
  const rng = mulberry32(seed + (response.visibility_score || 0));

  // Generate trend data based on visibility score (simulated historical)
  const baseScore = Math.max(20, response.visibility_score - 30);
  for (let i = 12; i >= 0; i--) {
    const date = new Date(now);
    date.setMonth(date.getMonth() - i);
    const variance = rng() * 10 - 5;
    const progressionFactor = (12 - i) / 12;
    const score = Math.round(baseScore + (response.visibility_score - baseScore) * progressionFactor + variance);

    let label: string | undefined;
    if (i === 9) label = "Start";
    if (i === 6) label = "Growth";
    if (i === 0) label = "Current";

    trendData.push({
      date: date.toLocaleDateString("en-US", { month: "short", year: "2-digit" }),
      visibility: Math.min(100, Math.max(0, score)),
      label,
    });
  }

  // Transform keywords from topical_keywords
  const keywords: KeywordData[] = (response.topical_keywords || []).slice(0, 5).map((kw, idx) => ({
    keyword: kw,
    position: 200 + idx + Math.floor(rng() * 15),
    volume: Math.floor(rng() * 20000) + 5000,
    traffic: rng() > 0.3 ? `+${Math.floor(rng() * 90)}K` : `-${Math.floor(rng() * 20)}K`,
    trend: rng() > 0.3 ? "up" as const : "down" as const,
  }));

  // Transform recommendations to insights
  const insightIcons = [
    <Zap className="w-5 h-5" />,
    <Activity className="w-5 h-5" />,
    <Target className="w-5 h-5" />,
  ];
  const insightColors: Array<"cyan" | "purple" | "coral"> = ["cyan", "purple", "coral"];

  const insights: Insight[] = (response.recommendations || []).slice(0, 3).map((rec, idx) => ({
    id: rec.id || String(idx + 1),
    icon: insightIcons[idx % 3],
    title: rec.title,
    description: rec.description || rec.impact,
    color: insightColors[idx % 3],
  }));

  // Create SERP results from key_takeaways or brand_entities
  const serpResults: SERPResult[] = [];
  const takeaways = response.key_takeaways || [];
  const brands = response.brand_entities || [];

  if (takeaways.length > 0) {
    serpResults.push({
      rank: 1,
      title: takeaways[0]?.substring(0, 50) || "Primary Content",
      url: response.domain_intelligence?.domain || response.url,
      type: "organic",
    });
  }
  if (takeaways.length > 1 || response.schema_markup?.has_faq_schema) {
    serpResults.push({
      rank: 2,
      title: takeaways[1]?.substring(0, 50) || "FAQ Content",
      url: response.domain_intelligence?.domain || response.url,
      type: "featured",
    });
  }
  if (brands.length > 0) {
    serpResults.push({
      rank: 3,
      title: brands[0] || "Brand Presence",
      url: response.domain_intelligence?.domain || response.url,
      type: "video",
    });
  }

  // Calculate derived metrics
  const contentScore = response.content_analysis?.word_count || 0;
  const schemaScore = (response.schema_markup?.json_ld_count || 0) * 100;

  return {
    visibilityScore: response.visibility_score,
    previousScore: Math.max(0, response.visibility_score - Math.floor(rng() * 15) - 5),
    organicTraffic: contentScore * 100 + schemaScore * 50,
    trafficChange: rng() > 0.5 ? Math.floor(rng() * 20) : -Math.floor(rng() * 15),
    rankingKeywords: (response.topical_keywords?.length || 0) * 100 + Math.floor(rng() * 500),
    keywordsChange: Math.floor(rng() * 300) + 50,
    topPositions: Math.floor(response.visibility_score * 3) + Math.floor(rng() * 50),
    positionsChange: rng() > 0.5 ? Math.floor(rng() * 20) : -Math.floor(rng() * 15),
    trendData,
    keywords: keywords.length > 0 ? keywords : generateDefaultKeywords(),
    serpResults: serpResults.length > 0 ? serpResults : generateDefaultSerpResults(),
    insights: insights.length > 0 ? insights : generateDefaultInsights(),
    url: response.url,
    analyzedAt: response.analyzed_at,
    summary: response.summary,
    aiPlatformScores: response.ai_platform_scores,
  };
}

