// Generate initial demo data
function generateDemoData(): DashboardData {
  const trendData: TrendDataPoint[] = [];
  const now = new Date();
  const demoRng = mulberry32(xmur3('demo')());

  for (let i = 24; i >= 0; i--) {
    const date = new Date(now);
    date.setMonth(date.getMonth() - i);
    const baseScore = 45 + demoRng() * 30;
    let label: string | undefined;

    if (i === 18) label = "High";
    if (i === 12) label = "Growth";
    if (i === 6) label = "Dip";

    trendData.push({
      date: date.toLocaleDateString("en-US", { month: "short", year: "2-digit" }),
      visibility: Math.round(baseScore + (24 - i) * 1.2),
      label,
    });
  }

  return {
    visibilityScore: 78,
    previousScore: 65,
    organicTraffic: 235000,
    trafficChange: -12,
    rankingKeywords: 1800,
    keywordsChange: 320,
    topPositions: 245,
    positionsChange: -15,
    trendData,
    keywords: generateDefaultKeywords(),
    serpResults: generateDefaultSerpResults(),
    insights: generateDefaultInsights(),
  };
}

// Stat Card Component
interface StatCardProps {
  title: string;
  value: string | number;
  change?: number;
  changeLabel?: string;
  badge?: string;
  badgeColor?: string;
  icon?: React.ReactNode;
  showProgress?: boolean;
  progressValue?: number;
}

function StatCard({
  title,
  value,
  change,
  changeLabel,
  badge,
  badgeColor = "emerald",
  showProgress,
  progressValue,
}: StatCardProps) {
  const isPositive = change !== undefined && change >= 0;

  return (
    <div className="relative group">
      {/* Glow effect */}
      <div className="absolute -inset-0.5 bg-gradient-to-r from-cyan-500/20 to-purple-500/20 rounded-2xl blur opacity-0 group-hover:opacity-100 transition duration-500" />

      <div className="relative bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-5 hover:border-cyan-500/30 transition-all duration-300">
        <p className="text-slate-400 text-sm font-medium mb-2">{title}</p>

        <div className="flex items-end gap-3">
          <span className="text-4xl font-bold text-white tracking-tight">{value}</span>

          {badge && (
            <span className={`px-2.5 py-1 rounded-full text-xs font-semibold bg-${badgeColor}-500/20 text-${badgeColor}-400 border border-${badgeColor}-500/30`}>
              {badge}
            </span>
          )}
        </div>

        {showProgress && progressValue !== undefined && (
          <div className="mt-4 h-2 bg-slate-800 rounded-full overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-full transition-all duration-1000"
              style={{ width: `${progressValue}%` }}
            />
          </div>
        )}

        {change !== undefined && (
          <div className={`flex items-center gap-1.5 mt-3 text-sm ${isPositive ? "text-emerald-400" : "text-red-400"}`}>
            {isPositive ? (
              <TrendingUp className="w-4 h-4" />
            ) : (
              <TrendingDown className="w-4 h-4" />
            )}
            <span className="font-medium">
              {isPositive ? "+" : ""}{change}%
            </span>
            {changeLabel && <span className="text-slate-500">{changeLabel}</span>}
          </div>
        )}
      </div>
    </div>
  );
}

// Visibility Trend Chart Component
interface VisibilityTrendProps {
  data: TrendDataPoint[];
  currentScore: number;
  previousScore: number;
}

function VisibilityTrend({ data, currentScore, previousScore }: VisibilityTrendProps) {
  const [timeRange, setTimeRange] = useState<"6M" | "1Y" | "All">("1Y");

  const filteredData = useMemo(() => {
    if (timeRange === "6M") return data.slice(-6);
    if (timeRange === "1Y") return data.slice(-12);
    return data;
  }, [data, timeRange]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-slate-800/95 backdrop-blur-sm border border-slate-700 rounded-lg px-3 py-2 shadow-xl">
          <p className="text-cyan-400 font-semibold">{payload[0].value}%</p>
          <p className="text-slate-400 text-xs">{payload[0].payload.date}</p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="relative group">
      <div className="absolute -inset-0.5 bg-gradient-to-r from-cyan-500/10 to-purple-500/10 rounded-2xl blur opacity-0 group-hover:opacity-100 transition duration-500" />

      <div className="relative bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-lg font-semibold text-white">Visibility Trend</h3>

          <div className="flex items-center gap-2">
            {/* Time range buttons */}
            <div className="flex bg-slate-800/80 rounded-lg p-1">
              {(["6M", "1Y", "All"] as const).map((range) => (
                <button
                  key={range}
                  onClick={() => setTimeRange(range)}
                  className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                    timeRange === range
                      ? "bg-cyan-500/20 text-cyan-400 border border-cyan-500/30"
                      : "text-slate-400 hover:text-white"
                  }`}
                >
                  {range}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="flex gap-6">
          {/* Globe visualization placeholder */}
          <div className="hidden lg:flex items-center justify-center w-48 h-48 relative">
            <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/10 to-purple-500/10 rounded-full blur-2xl" />
            <div className="relative w-36 h-36 rounded-full border border-cyan-500/30 bg-slate-900/50 flex items-center justify-center">
              <Globe className="w-16 h-16 text-cyan-500/50" />
              <div className="absolute inset-0 rounded-full border border-cyan-500/20 animate-ping" style={{ animationDuration: "3s" }} />
            </div>
          </div>

          {/* Chart */}
          <div className="flex-1 h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={filteredData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id="visibilityGradient" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor="#06b6d4" stopOpacity={0.3} />
                    <stop offset="100%" stopColor="#06b6d4" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis
                  dataKey="date"
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: "#64748b", fontSize: 11 }}
                />
                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tick={{ fill: "#64748b", fontSize: 11 }}
                  domain={[0, 100]}
                />
                <Tooltip content={<CustomTooltip />} />
                <Area
                  type="monotone"
                  dataKey="visibility"
                  stroke="#06b6d4"
                  strokeWidth={2}
                  fill="url(#visibilityGradient)"
                  dot={false}
                  activeDot={{ r: 6, fill: "#06b6d4", stroke: "#0f172a", strokeWidth: 2 }}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>

          {/* Current stats */}
          <div className="hidden md:flex flex-col justify-center gap-4 min-w-[140px]">
            <div>
              <p className="text-slate-500 text-xs uppercase tracking-wider">Current Visibility</p>
              <p className="text-3xl font-bold text-white">{currentScore}<span className="text-cyan-400">%</span></p>
            </div>
            <div>
              <p className="text-slate-500 text-xs uppercase tracking-wider">Previous</p>
              <p className="text-xl font-semibold text-slate-400">{previousScore}%</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

