// AI Platform Scores Component
interface AIPlatformScoresProps {
  scores?: {
    chatgpt: number;
    perplexity: number;
    google_ai: number;
    claude: number;
  };
}

function AIPlatformScores({ scores }: AIPlatformScoresProps) {
  if (!scores) return null;

  const platforms = [
    { key: "chatgpt", name: "ChatGPT", color: "from-emerald-500 to-green-600", icon: "🤖" },
    { key: "perplexity", name: "Perplexity", color: "from-blue-500 to-cyan-600", icon: "🔍" },
    { key: "google_ai", name: "Google AI", color: "from-yellow-500 to-orange-600", icon: "🔎" },
    { key: "claude", name: "Claude", color: "from-purple-500 to-pink-600", icon: "🧠" },
  ];

  return (
    <div className="relative group">
      <div className="absolute -inset-0.5 bg-gradient-to-r from-cyan-500/10 to-purple-500/10 rounded-2xl blur opacity-0 group-hover:opacity-100 transition duration-500" />

      <div className="relative bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 rounded-2xl p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 rounded-lg bg-gradient-to-br from-cyan-500/20 to-purple-500/20">
            <Eye className="w-5 h-5 text-cyan-400" />
          </div>
          <h3 className="text-lg font-semibold text-white">AI Platform Visibility</h3>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {platforms.map((platform) => {
            const score = scores[platform.key as keyof typeof scores] || 0;
            return (
              <div
                key={platform.key}
                className="relative overflow-hidden rounded-xl bg-slate-800/50 border border-slate-700/30 p-4 hover:border-slate-600/50 transition-all"
              >
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">{platform.icon}</span>
                  <span className="text-sm font-medium text-slate-300">{platform.name}</span>
                </div>

                <div className="text-2xl font-bold text-white mb-2">
                  {score}<span className="text-sm text-slate-400 font-normal">/100</span>
                </div>

                {/* Progress bar */}
                <div className="h-1.5 bg-slate-700 rounded-full overflow-hidden">
                  <div
                    className={`h-full bg-gradient-to-r ${platform.color} rounded-full transition-all duration-1000`}
                    style={{ width: `${score}%` }}
                  />
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

