import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { CanonicalTier } from '../../types';

const API_URL = import.meta.env.VITE_API_URL || '';

interface UserFeatures {
  exports: boolean;
  forceRefresh: boolean;
  apiAccess: boolean;
  whiteLabel: boolean;
  scheduledRescans: boolean;
  reportHistory: boolean;
  shareableLink: boolean;
  multiPageCrawl: boolean;
  competitorDiff: boolean;
}

interface UserLimits {
  scansPerMonth: number;
  pagesPerScan: number;
  competitors: number;
  cacheDays: number;
}

interface User {
  id: string;
  email: string;
  tier: CanonicalTier;
  full_name?: string;
}

interface Entitlements {
  tier: CanonicalTier;
  features: UserFeatures;
  limits: UserLimits;
}

interface AuthState {
  // State
  user: User | null;
  token: string | null;
  isAuthenticated: boolean;
  entitlements: Entitlements | null;
  isRefreshing: boolean;

  // Actions
  setUser: (user: User | null) => void;
  setToken: (token: string | null) => void;
  setEntitlements: (entitlements: Entitlements | null) => void;
  login: (user: User, token: string, entitlements?: Entitlements) => void;
  logout: () => void;
  refreshUser: () => Promise<boolean>;
  hasFeature: (feature: keyof UserFeatures) => boolean;
  getLimit: (limit: keyof UserLimits) => number;
}

export const useAuthStore = create<AuthState>()(
  persist(
    (set, get) => ({
      user: null,
      token: null,
      isAuthenticated: false,
      entitlements: null,
      isRefreshing: false,

      setUser: (user) => set({ user, isAuthenticated: !!user }),

      setToken: (token) => set({ token }),

      setEntitlements: (entitlements) => set({ entitlements }),

      login: (user, token, entitlements) =>
        set({
          user,
          token,
          isAuthenticated: true,
          entitlements: entitlements || null,
        }),

      logout: () =>
        set({
          user: null,
          token: null,
          isAuthenticated: false,
          entitlements: null,
        }),

      /**
       * Refresh user data from the server
       * Call this after payment success to get updated tier/entitlements
       */
      refreshUser: async () => {
        const { token } = get();
        if (!token) return false;

        set({ isRefreshing: true });

        try {
          const response = await fetch(`${API_URL}/api/user/refresh`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`,
            },
          });

          if (!response.ok) {
            console.error('Failed to refresh user:', response.status);
            return false;
          }

          const data = await response.json();

          if (data.success) {
            set({
              user: data.user,
              token: data.token || token, // Use new token if provided
              entitlements: data.entitlements,
              isAuthenticated: true,
            });
            return true;
          }

          return false;
        } catch (error) {
          console.error('Error refreshing user:', error);
          return false;
        } finally {
          set({ isRefreshing: false });
        }
      },

      /**
       * Check if user has access to a specific feature
       */
      hasFeature: (feature) => {
        const { entitlements } = get();
        return entitlements?.features[feature] ?? false;
      },

      /**
       * Get the limit value for a specific limit type
       */
      getLimit: (limit) => {
        const { entitlements } = get();
        return entitlements?.limits[limit] ?? 0;
      },
    }),
    {
      name: 'auth-storage', // localStorage key
      partialize: (state) => ({
        token: state.token,
        user: state.user,
        isAuthenticated: state.isAuthenticated,
        entitlements: state.entitlements,
      }),
    }
  )
);

/**
 * Hook to check feature access
 */
export function useFeatureAccess(feature: keyof UserFeatures): boolean {
  const { entitlements, isAuthenticated } = useAuthStore();
  if (!isAuthenticated || !entitlements) return false;
  return entitlements.features[feature];
}

/**
 * Hook to get tier limits
 */
export function useTierLimits(): UserLimits | null {
  const { entitlements, isAuthenticated } = useAuthStore();
  if (!isAuthenticated || !entitlements) return null;
  return entitlements.limits;
}
